/* reveal */
const io=new IntersectionObserver(es=>{es.forEach(e=>{if(e.isIntersecting){e.target.classList.add('in');io.unobserve(e.target);}});},{threshold:0.12,rootMargin:'0px 0px -50px 0px'});
document.querySelectorAll('.reveal').forEach(el=>io.observe(el));

/* count-up */
function count(el){const t=+el.dataset.target,suf=el.dataset.suffix||'',pad=+el.dataset.pad||0,dur=1500,s=performance.now();function step(n){const p=Math.min((n-s)/dur,1),e=1-Math.pow(1-p,3);let v=Math.round(t*e),txt=pad?String(v).padStart(pad,'0'):String(v);el.innerHTML=(pad?`<span class="u">${txt}</span>`:txt)+suf;if(p<1)requestAnimationFrame(step);}requestAnimationFrame(step);}
const cio=new IntersectionObserver(es=>{es.forEach(e=>{if(e.isIntersecting){count(e.target);cio.unobserve(e.target);}});},{threshold:0.5});
document.querySelectorAll('[data-target]').forEach(el=>cio.observe(el));

